selector_to_html = {"a[href=\"#id1\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">5.4.1 </span>Sensor Interfaces<a class=\"headerlink\" href=\"#id1\" title=\"Link to this heading\">\uf0c1</a></h1><p><strong>The sensor interfaces provide data access and control for the robot\u2019s various sensors, including cameras, IMUs, LiDAR, and touch sensors.</strong></p>", "a[href=\"#interface-lidar\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">LiDAR Topics<a class=\"headerlink\" href=\"#interface-lidar\" title=\"Link to this heading\">\uf0c1</a></h2><p>Provides LiDAR point clouds and LiDAR-integrated IMU data for obstacle avoidance and SLAM/localization.<br/>\nThe LiDAR is on the development compute unit (PC2) with data bandwidth on the order of 10 MB/s \u2014 cross-unit subscriptions are <strong>not recommended</strong>.</p>", "a[href=\"#id3\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">Vision Sensors<a class=\"headerlink\" href=\"#id3\" title=\"Link to this heading\">\uf0c1</a></h3>", "a[href=\"#id8\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Stereo Camera Topics<a class=\"headerlink\" href=\"#id8\" title=\"Link to this heading\">\uf0c1</a></h2><p>The stereo camera is on the development compute unit (PC2) and can be used for stereo vision, teleoperation, obstacle perception, object recognition, VIO SLAM, VLA and more.<br/>\nRaw image bandwidth is about 90 MB/s per eye \u2014 <strong>use only on the same compute unit, do not subscribe across units.</strong></p>", "a[href=\"#id11\"]": "<figure class=\"align-center\" id=\"id11\">\n<a class=\"reference internal image-reference\" href=\"../../_images/camera_head_rear_obstructed.jpg\"><img alt=\"\u540e\u89c6RGB\u76f8\u673a\u906e\u6321\u793a\u610f\u56fe\" src=\"../../_images/camera_head_rear_obstructed.jpg\" style=\"width: 100%;\"/>\n</a>\n<figcaption>\n<p><span class=\"caption-text\">Rear RGB Camera - Obstructed View Diagram</span><a class=\"headerlink\" href=\"#id11\" title=\"Link to this image\">\uf0c1</a></p>\n</figcaption>\n</figure>", "a[href=\"../../example/Cpp.html#cpp-echo-camera-head-rear\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">Rear Head Monocular Camera Data Subscription<a class=\"headerlink\" href=\"#cpp-echo-camera-head-rear\" title=\"Link to this heading\">\uf0c1</a></h3><p><strong>This example uses echo_camera_head_rear</strong>, subscribing to the <code class=\"docutils literal notranslate\"><span class=\"pre\">/aima/hal/sensor/rgb_head_rear/</span></code> topic to receive data from the robot\u2019s rear head monocular camera, supporting RGB images (with/without mask), compressed images, and camera intrinsic parameters.</p><p><strong>Features:</strong></p>", "a[href=\"../../example/Cpp.html\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">6.2 </span>C++ Interface Usage Example<a class=\"headerlink\" href=\"#c\" title=\"Link to this heading\">\uf0c1</a></h1><p><strong>This section will guide you through implementing the functions listed in the index</strong></p><p><strong>Build &amp; Run Instructions</strong></p>", "a[href=\"#id10\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Safety Notes<a class=\"headerlink\" href=\"#id10\" title=\"Link to this heading\">\uf0c1</a></h2>", "a[href=\"../../example/Python.html\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">6.1 </span>Python interface usage example<a class=\"headerlink\" href=\"#python\" title=\"Link to this heading\">\uf0c1</a></h1><p><strong>This chapter will guide you through implementing several features shown in the index</strong></p><p><strong>Build &amp; Run Instructions</strong></p>", "a[href=\"#id6\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Standard Sensor Messages<a class=\"headerlink\" href=\"#id6\" title=\"Link to this heading\">\uf0c1</a></h2><p>Most sensor interfaces use the standard message types defined in ROS <code class=\"docutils literal notranslate\"><span class=\"pre\">sensor_msgs</span></code>:</p>", "a[href=\"#id4\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">Pose Sensors<a class=\"headerlink\" href=\"#id4\" title=\"Link to this heading\">\uf0c1</a></h3>", "a[href=\"#id5\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">Environmental Perception Sensors<a class=\"headerlink\" href=\"#id5\" title=\"Link to this heading\">\uf0c1</a></h3>", "a[href=\"#rgb\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Rear RGB Camera Topics<a class=\"headerlink\" href=\"#rgb\" title=\"Link to this heading\">\uf0c1</a></h2><p>The rear RGB camera is on the development compute unit (PC2) and can be used for visual localization assistance and semantic scene understanding.<br/>\nRaw image bandwidth is about 90 MB/s \u2014 <strong>use only on the same compute unit, do not subscribe across units.</strong></p>", "a[href=\"#id9\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Code Examples<a class=\"headerlink\" href=\"#id9\" title=\"Link to this heading\">\uf0c1</a></h2><p>For detailed code samples and explanations, see:</p>", "a[href=\"#id7\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Head Touch Status Topic<a class=\"headerlink\" href=\"#id7\" title=\"Link to this heading\">\uf0c1</a></h2><p>Supported features:</p>", "a[href=\"#interface-rgbd-camera\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">RGB-D Camera Topics<a class=\"headerlink\" href=\"#interface-rgbd-camera\" title=\"Link to this heading\">\uf0c1</a></h2><p>The RGB-D camera is on the development compute unit (PC2) and can be used for object detection, spatial obstacle avoidance, and semantic environment understanding.<br/>\n<strong>Raw image bandwidth is about 25 MB/s per stream \u2014 use only on the same compute unit, do not subscribe across units.</strong></p>", "a[href=\"#imu\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">IMU Topics<a class=\"headerlink\" href=\"#imu\" title=\"Link to this heading\">\uf0c1</a></h2><p>Includes chest IMU and torso IMU, both located on the development compute unit (PC2).<br/>\nYou can also use the IMUs integrated in <a class=\"reference internal\" href=\"#interface-lidar\">LiDAR</a> and the <a class=\"reference internal\" href=\"#interface-rgbd-camera\">RGB-D camera</a>.</p>", "a[href=\"#id2\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Core Features<a class=\"headerlink\" href=\"#id2\" title=\"Link to this heading\">\uf0c1</a></h2><h3>Vision Sensors<a class=\"headerlink\" href=\"#id3\" title=\"Link to this heading\">\uf0c1</a></h3>"}
skip_classes = ["headerlink", "sd-stretched-link"]

window.onload = function () {
    for (const [select, tip_html] of Object.entries(selector_to_html)) {
        const links = document.querySelectorAll(` ${select}`);
        for (const link of links) {
            if (skip_classes.some(c => link.classList.contains(c))) {
                continue;
            }

            tippy(link, {
                content: tip_html,
                allowHTML: true,
                arrow: true,
                placement: 'auto-start', maxWidth: 500, interactive: false, theme: 'material', duration: [300, 200], delay: [200, 100],

            });
        };
    };
    console.log("tippy tips loaded!");
};
